module gray_code_counter(CLK, RST, Q);
input CLK, RST;
output [2:0] Q;
reg [2:0] Q;
reg [2:0] gray_code;

always @(posedge CLK or posedge RST) begin
    if (RST) begin
        gray_code <= 0;
        Q <= 0;
    end else begin
        gray_code <= gray_code + 1;
        Q <= (gray_code >> 1) ^ gray_code; // Convert binary to gray code
    end
end

endmodule
